define i1 @or_and2_commuted(i1 %a, i1 %b, i1 %c) {
  %notc = xor i1 %c, true
  %cond = or i1 %a, %notc
  %r = select i1 %cond, i1 %a, i1 %b
  ret i1 %r
}

